{
  "schemaVersion": 2,
  "id": "code-clarity-pack",
  "name": "Code Clarity Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "ui-snippet",
  "capabilities": [
    "theme.snippet"
  ],
  "platforms": [
    "desktop",
    "web"
  ],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [],
      "snippets": [
        {
          "file": "theme/snippets/code-gutter-solid-pack.css",
          "id": "code-gutter-solid-pack",
          "label": "Solid Code Gutter",
          "description": "Opaque code gutters to prevent line-number overlap.",
          "defaultEnabled": true
        },
        {
          "file": "theme/snippets/crisp-code-shadow-pack.css",
          "id": "crisp-code-shadow-pack",
          "label": "Crisp Code Shadow",
          "description": "Sharper fenced code block edges and hover feedback.",
          "defaultEnabled": false
        }
      ],
      "tokens": [],
      "defaultEnable": {
        "snippets": [
          "code-gutter-solid-pack"
        ]
      }
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * code-gutter-solid
 * Force opaque code gutters to avoid overlap artifacts.
 */

html[data-theme='light'],
html[data-theme='dark'] {
  --code-gutter-bg: color-mix(in srgb, var(--code-bg) 88%, var(--surface-app));
}

.preview-pane .markdown-pre-linenos,
.preview-pane.markdown-visual-editor .ProseMirror .pm-code-linenos,
.preview-pane.markdown-visual-editor .ProseMirror .pm-code-block-cm .cm-gutters {
  opacity: 1 !important;
  background: var(--code-gutter-bg, var(--code-bg)) !important;
  mix-blend-mode: normal;
  backdrop-filter: none;
}

/**
 * crisp-code-shadow
 * Sharper fenced code edges for better structure scanning.
 */

.preview-pane.markdown-visual-editor .ProseMirror .pm-code-block-surface,
.preview-pane .markdown-pre-figure {
  box-shadow:
    inset 0 0 0 var(--hairline) color-mix(in srgb, var(--border-subtle) 92%, transparent),
    0 6px 18px color-mix(in srgb, #000 10%, transparent) !important;
}

.preview-pane.markdown-visual-editor .ProseMirror .pm-code-block-wrap:hover .pm-code-block-surface {
  box-shadow:
    inset 0 0 0 var(--hairline) color-mix(in srgb, var(--accent) 24%, var(--border-subtle)),
    0 10px 22px color-mix(in srgb, #000 14%, transparent) !important;
}
